
#ifndef PROJECTM_EXPORT_H
#define PROJECTM_EXPORT_H

// Y2Kmeter note:
// We do not link libprojectM at build time; the DLL is loaded dynamically via
// LoadLibrary()/GetProcAddress() at runtime. Therefore PROJECTM_EXPORT is left
// empty here, so the C API function declarations in the projectM-4 headers
// compile as regular extern "C" prototypes without dllimport/dllexport
// decoration. This lets us reuse the upstream headers verbatim.
//
// If you ever switch to link-time consumption, replace the definitions below
// with the ones generated by CMake's GenerateExportHeader (dllimport on
// consumer side, dllexport on producer side).

#define PROJECTM_EXPORT
#define PROJECTM_NO_EXPORT
#define PROJECTM_DEPRECATED
#define PROJECTM_DEPRECATED_EXPORT
#define PROJECTM_DEPRECATED_NO_EXPORT

#endif // PROJECTM_EXPORT_H
